import React, { useState, useEffect } from 'react';
import { QRCodeCanvas } from 'qrcode.react';
import { useNavigate } from 'react-router-dom';
import './Registration.css';
import { saveFormData } from '../db/indexedDB';

const Registration = () => {
    const [formData, setFormData] = useState({
        type: 'staff',
        additionalFields: {},
    });
    const [message, setMessage] = useState('');
    const [suppliers, setSuppliers] = useState([]);
    const [qrCodeData, setQrCodeData] = useState('');
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        const fetchSuppliers = async () => {
            try {
                const response = await fetch('http://localhost:8000/api/v1/suppliers');
                const data = await response.json();
                setSuppliers(data);
            } catch (error) {
                console.error('Error fetching suppliers:', error);
            }
        };

        fetchSuppliers();
    }, []);

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormData({ ...formData, [name]: value });
    };

    const handleAdditionalFieldsChange = (e) => {
        const { name, value } = e.target;
        setFormData({
            ...formData,
            additionalFields: { ...formData.additionalFields, [name]: value },
        });
    };

    const calculateAge = (dob) => {
        const birthDate = new Date(dob);
        const today = new Date();
        let age = today.getFullYear() - birthDate.getFullYear();
        const monthDiff = today.getMonth() - birthDate.getMonth();
        if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birthDate.getDate())) {
            age--;
        }
        return age;
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setMessage('');
        try {
            let endpoint = '';
            let payload = {};
            const type = formData.type;
            const fields = formData.additionalFields;
            // Map frontend fields to backend payloads and endpoints
            switch (type) {
                case 'staff':
                    endpoint = 'http://localhost:8000/api/v1/registration/staff';
                    payload = {
                        name: fields.staffName,
                        staff_id: fields.staffId || `ASTRO${Math.floor(1000 + Math.random() * 9000)}`,
                        dob: fields.dob,
                        gender: fields.gender,
                        phone: fields.phone,
                        address: fields.address, // Now required
                        bank: fields.bankName, // Now required
                        account_number: fields.accountNumber, // Already present
                        hourly_rate: fields.hourlyRate ? parseFloat(fields.hourlyRate) : 0, // Now required
                        role: fields.role || 'staff',
                        department: fields.department, // Now required
                        appointment_type: fields.appointmentType, // Now required
                    };
                    break;
                case 'product':
                    endpoint = 'http://localhost:8000/api/v1/registration/product';
                    payload = {
                        name: fields.productName,
                        product_id: fields.productId || undefined,
                        description: fields.productDescription,
                        uom: fields.unitOfMeasure,
                        source: fields.source || '',
                        unit_price: fields.unitPrice ? parseFloat(fields.unitPrice) : 0,
                        reorder_point: fields.reorderPoint ? parseInt(fields.reorderPoint) : 0,
                        opening_stock: fields.openingStockQuantity ? parseInt(fields.openingStockQuantity) : 0,
                    };
                    break;
                case 'raw_material':
                    endpoint = 'http://localhost:8000/api/v1/registration/raw-material';
                    payload = {
                        name: fields.rawMaterialName,
                        rm_id: fields.rawMaterialId || undefined,
                        category: fields.category || '',
                        source: fields.source || '',
                        uom: fields.unitOfMeasure,
                        reorder_point: fields.reorderPoint ? parseInt(fields.reorderPoint) : 0,
                        unit_cost: fields.unitPrice ? parseFloat(fields.unitPrice) : 0,
                        opening_stock: fields.openingStockQuantity ? parseInt(fields.openingStockQuantity) : 0,
                    };
                    break;
                case 'customer':
                    endpoint = 'http://localhost:8000/api/v1/registration/customer';
                    payload = {
                        name: fields.customerName,
                        company: fields.company || '',
                        phone: fields.phoneNumber,
                        address: fields.address || '',
                    };
                    break;
                case 'warehouse':
                    endpoint = 'http://localhost:8000/api/v1/registration/warehouse';
                    payload = {
                        name: fields.warehouseName,
                        wh_id: fields.warehouseId || `WH${Math.floor(1000 + Math.random() * 9000)}`,
                        location: fields.location,
                        manager_name: fields.manager,
                        manager_phone: fields.managerPhone,
                        date_created: new Date().toISOString().split('T')[0],
                    };
                    break;
                case 'supplier':
                    endpoint = 'http://localhost:8000/api/v1/registration/supplier';
                    payload = {
                        name: fields.supplierName,
                        phone: fields.contactPhone,
                        country: fields.country || '',
                        state: fields.state || '',
                    };
                    break;
                case 'distributor':
                    endpoint = 'http://localhost:8000/api/v1/registration/distributor';
                    payload = {
                        name: fields.distributorName,
                        dist_id: fields.distributorId || `DIST${Math.floor(1000 + Math.random() * 9000)}`,
                        phone: fields.phoneNumber,
                        coverage: fields.region,
                        address: fields.address || '',
                    };
                    break;
                case 'marketer':
                    endpoint = 'http://localhost:8000/api/v1/registration/marketer';
                    payload = {
                        name: fields.marketerName,
                        mark_id: fields.marketerId || `MARK${Math.floor(1000 + Math.random() * 9000)}`,
                        coverage: fields.region || '',
                        phone: fields.phoneNumber,
                        email: fields.email || '',
                    };
                    break;
                default:
                    setMessage('Invalid registration type.');
                    setLoading(false);
                    return;
            }
            const response = await fetch(endpoint, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(payload),
            });
            let data;
            try {
                data = await response.json();
            } catch (jsonErr) {
                data = {};
            }
            if (response.ok) {
                setMessage('Registration successful!');
                setQrCodeData(JSON.stringify(payload));
                await saveFormData(payload);
                setFormData({ type: 'staff', additionalFields: {} });
                setLoading(false);
            } else {
                let errorMsg = 'Registration failed. Please try again.';
                if (data.detail) {
                    if (typeof data.detail === 'string') {
                        errorMsg = data.detail;
                    } else if (Array.isArray(data.detail)) {
                        errorMsg = data.detail.map(d => d.msg || JSON.stringify(d)).join('; ');
                    } else if (typeof data.detail === 'object') {
                        errorMsg = JSON.stringify(data.detail);
                    }
                }
                setMessage(errorMsg);
                setLoading(false);
            }
        } catch (error) {
            setMessage('An error occurred. Please try again.');
            setLoading(false);
        }
    };

    return (
        <div className="registration-container">
            <h1>Registration</h1>
            <form onSubmit={handleSubmit} className="registration-form">
                <label>
                    Type:
                    <select
                        name="type"
                        value={formData.type || ''}
                        onChange={handleInputChange}
                        required
                    >
                        <option value="">Select Type</option>
                        <option value="staff">Staff</option>
                        <option value="product">Product</option>
                        <option value="raw_material">Raw Material</option>
                        <option value="customer">Customer</option>
                        <option value="warehouse">Warehouse</option>
                        <option value="supplier">Supplier</option>
                        <option value="distributor">Distributor</option>
                        <option value="marketer">Marketer</option>
                    </select>
                </label>
                {formData.type === 'staff' && (
                    <div>
                        <label>
                            Staff Name:
                            <input
                                type="text"
                                name="staffName"
                                value={formData.additionalFields?.staffName || ''}
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Staff ID (Auto-generated):
                            <input
                                type="text"
                                name="staffId"
                                value={`ASTRO${Math.floor(1000 + Math.random() * 9000)}`}
                                readOnly
                            />
                        </label>
                        <label>
                            Date of Birth:
                            <input
                                type="date"
                                name="dob"
                                onChange={(e) => {
                                    handleAdditionalFieldsChange(e);
                                    setFormData({
                                        ...formData,
                                        additionalFields: {
                                            ...formData.additionalFields,
                                            age: calculateAge(e.target.value),
                                        },
                                    });
                                }}
                                required
                            />
                        </label>
                        <label>
                            Age (Auto-calculated):
                            <input
                                type="number"
                                name="age"
                                value={formData.additionalFields.age || ''}
                                readOnly
                            />
                        </label>
                        <label>
                            Gender:
                            <select
                                name="gender"
                                onChange={handleAdditionalFieldsChange}
                                required
                            >
                                <option value="">Select Gender</option>
                                <option value="male">Male</option>
                                <option value="female">Female</option>
                            </select>
                        </label>
                        <label>
                            Marital Status:
                            <select
                                name="maritalStatus"
                                onChange={handleAdditionalFieldsChange}
                                required
                            >
                                <option value="">Select Status</option>
                                <option value="single">Single</option>
                                <option value="married">Married</option>
                                <option value="divorced">Divorced</option>
                                <option value="widow">Widow</option>
                                <option value="widowed">Widowed</option>
                            </select>
                        </label>
                        <label>
                            Contact Phone Number:
                            <input
                                type="text"
                                name="phone"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Email Address (Optional):
                            <input
                                type="email"
                                name="email"
                                onChange={handleAdditionalFieldsChange}
                            />
                        </label>
                        <label>
                            Next of Kin Name:
                            <input
                                type="text"
                                name="nextOfKinName"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Next of Kin Phone Number:
                            <input
                                type="text"
                                name="nextOfKinPhone"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Bank Name:
                            <input
                                type="text"
                                name="bankName"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Account Number:
                            <input
                                type="text"
                                name="accountNumber"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                    </div>
                )}
                {formData.type === 'product' && (
                    <div>
                        <label>
                            Product Name:
                            <input
                                type="text"
                                name="productName"
                                value={formData.additionalFields?.productName || ''}
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Product ID (Auto-generated):
                            <input
                                type="text"
                                name="productId"
                                value="Auto-generated"
                                readOnly
                            />
                        </label>
                        <label>
                            Product Description:
                            <textarea
                                name="productDescription"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Unit of Measure:
                            <input
                                type="text"
                                name="unitOfMeasure"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            PR-Unit Price:
                            <input
                                type="number"
                                name="unitPrice"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            PR-Reorder Point:
                            <input
                                type="number"
                                name="reorderPoint"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Opening Stock Quantity:
                            <input
                                type="number"
                                name="openingStockQuantity"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Products Average Unit Production Time:
                            <input
                                type="text"
                                name="averageProductionTime"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <button type="button" onClick={() => window.location.href = '/inventory'}>
                            View Product List
                        </button>
                    </div>
                )}
                {formData.type === 'raw_material' && (
                    <div>
                        <label>
                            Raw Material Name:
                            <input
                                type="text"
                                name="rawMaterialName"
                                value={formData.additionalFields?.rawMaterialName || ''}
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Raw Material ID (Auto-generated):
                            <input
                                type="text"
                                name="rawMaterialId"
                                value="Auto-generated"
                                readOnly
                            />
                        </label>
                        <label>
                            Raw Material Description:
                            <textarea
                                name="rawMaterialDescription"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            RM-Unit of Measure:
                            <input
                                type="text"
                                name="unitOfMeasure"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            RM-Unit Price:
                            <input
                                type="number"
                                name="unitPrice"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            RM-Opening Stock Quantity:
                            <input
                                type="number"
                                name="openingStockQuantity"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Supplier:
                            <select
                                name="supplier"
                                onChange={handleAdditionalFieldsChange}
                                required
                            >
                                <option value="">Select a supplier</option>
                                {suppliers.map((supplier) => (
                                    <option key={supplier.id} value={supplier.id}>
                                        {supplier.name}
                                    </option>
                                ))}
                            </select>
                        </label>
                        <label>
                            RM-Reorder Point:
                            <input
                                type="number"
                                name="reorderPoint"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <button type="button" onClick={() => window.location.href = '/inventory'}>
                            View Raw Material List
                        </button>
                    </div>
                )}
                {formData.type === 'customer' && (
                    <div>
                        <label>
                            Customer Name:
                            <input
                                type="text"
                                name="customerName"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Customer ID (Auto-generated):
                            <input
                                type="text"
                                name="customerId"
                                value={`CUST${Math.floor(1000 + Math.random() * 9000)}`}
                                readOnly
                            />
                        </label>
                        <label>
                            Phone Number:
                            <input
                                type="text"
                                name="phoneNumber"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Address of Location:
                            <textarea
                                name="address"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <button type="button" onClick={() => window.location.href = '/customers-list'}>
                            View Customers List
                        </button>
                    </div>
                )}
                {formData.type === 'warehouse' && (
                    <div>
                        <label>
                            Warehouse Name:
                            <input
                                type="text"
                                name="warehouseName"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Location:
                            <input
                                type="text"
                                name="location"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Manager:
                            <input
                                type="text"
                                name="manager"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Manager Phone Number:
                            <input
                                type="text"
                                name="managerPhone"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                    </div>
                )}
                {formData.type === 'supplier' && (
                    <div>
                        <label>
                            Supplier Name:
                            <input
                                type="text"
                                name="supplierName"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Supplier ID (Auto-generated):
                            <input
                                type="text"
                                name="supplierId"
                                value={`SUP${Math.floor(1000 + Math.random() * 9000)}`}
                                readOnly
                            />
                        </label>
                        <label>
                            Contact Phone Number:
                            <input
                                type="text"
                                name="contactPhone"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Address of Supplier:
                            <textarea
                                name="address"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <button type="button" onClick={() => window.location.href = '/suppliers-list'}>
                            View Suppliers List
                        </button>
                    </div>
                )}
                {formData.type === 'distributor' && (
                    <div>
                        <label>
                            Distributor Name:
                            <input
                                type="text"
                                name="distributorName"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Distributor ID (Auto-generated):
                            <input
                                type="text"
                                name="distributorId"
                                value={`DIST${Math.floor(1000 + Math.random() * 9000)}`}
                                readOnly
                            />
                        </label>
                        <label>
                            Region of Coverage:
                            <select
                                name="region"
                                onChange={handleAdditionalFieldsChange}
                                required
                            >
                                <option value="">Select a state</option>
                                <option value="Abia">Abia</option>
                                <option value="Adamawa">Adamawa</option>
                                <option value="Akwa Ibom">Akwa Ibom</option>
                                <option value="Anambra">Anambra</option>
                                <option value="Bauchi">Bauchi</option>
                                <option value="Bayelsa">Bayelsa</option>
                                <option value="Benue">Benue</option>
                                <option value="Borno">Borno</option>
                                <option value="Cross River">Cross River</option>
                                <option value="Delta">Delta</option>
                                <option value="Ebonyi">Ebonyi</option>
                                <option value="Edo">Edo</option>
                                <option value="Ekiti">Ekiti</option>
                                <option value="Enugu">Enugu</option>
                                <option value="Gombe">Gombe</option>
                                <option value="Imo">Imo</option>
                                <option value="Jigawa">Jigawa</option>
                                <option value="Kaduna">Kaduna</option>
                                <option value="Kano">Kano</option>
                                <option value="Katsina">Katsina</option>
                                <option value="Kebbi">Kebbi</option>
                                <option value="Kogi">Kogi</option>
                                <option value="Kwara">Kwara</option>
                                <option value="Lagos">Lagos</option>
                                <option value="Nasarawa">Nasarawa</option>
                                <option value="Niger">Niger</option>
                                <option value="Ogun">Ogun</option>
                                <option value="Ondo">Ondo</option>
                                <option value="Osun">Osun</option>
                                <option value="Oyo">Oyo</option>
                                <option value="Plateau">Plateau</option>
                                <option value="Rivers">Rivers</option>
                                <option value="Sokoto">Sokoto</option>
                                <option value="Taraba">Taraba</option>
                                <option value="Yobe">Yobe</option>
                                <option value="Zamfara">Zamfara</option>
                                <option value="FCT">FCT</option>
                            </select>
                        </label>
                        <label>
                            Phone Number:
                            <input
                                type="text"
                                name="phoneNumber"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Email Address (Optional):
                            <input
                                type="email"
                                name="email"
                                onChange={handleAdditionalFieldsChange}
                            />
                        </label>
                    </div>
                )}
                {formData.type === 'marketer' && (
                    <div>
                        <label>
                            Marketer Name:
                            <input
                                type="text"
                                name="marketerName"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Marketer ID (Auto-generated):
                            <input
                                type="text"
                                name="marketerId"
                                value={`MARK${Math.floor(1000 + Math.random() * 9000)}`}
                                readOnly
                            />
                        </label>
                        <label>
                            Phone Number:
                            <input
                                type="text"
                                name="phoneNumber"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Address of Location:
                            <textarea
                                name="address"
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <button type="button" onClick={() => window.location.href = '/marketers-list'}>
                            View Marketers List
                        </button>
                    </div>
                )}
                <button type="submit" disabled={loading}>{loading ? 'Registering...' : 'Register'}</button>
            </form>
            {message && <div className={message.includes('success') ? 'success' : 'error'} style={{marginTop:'1rem'}}>{message}</div>}
            {qrCodeData && (
                <div className="qr-code">
                    <h3>QR Code:</h3>
                    <QRCodeCanvas value={qrCodeData} />
                </div>
            )}
        </div>
    );
};

export default Registration;
